import { useMemo, useState } from 'react';
import { LeaveCoveredStatus, type LeaveCoveredListParams } from '@/api/leaveService';

export function useLeaveCoverageFilters() {
    const [pageIndex, setPageIndex] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [statusFilter, setStatusFilter] = useState('');
    const [leaveIdFilter, setLeaveIdFilter] = useState('');
    const [coveredForFilter, setCoveredForFilter] = useState('');

    const listParams = useMemo<LeaveCoveredListParams>(
        () => ({
            pageIndex,
            pageSize,
            leaveId: leaveIdFilter || undefined,
            coveredForUserId: coveredForFilter || undefined,
            status: statusFilter === '' ? undefined : (Number(statusFilter) as LeaveCoveredStatus),
        }),
        [coveredForFilter, leaveIdFilter, pageIndex, pageSize, statusFilter]
    );

    const resetFilters = () => {
        setStatusFilter('');
        setLeaveIdFilter('');
        setCoveredForFilter('');
        setPageIndex(1);
    };

    return {
        pageIndex,
        pageSize,
        statusFilter,
        leaveIdFilter,
        coveredForFilter,
        setPageIndex,
        setPageSize,
        setStatusFilter,
        setLeaveIdFilter,
        setCoveredForFilter,
        listParams,
        resetFilters,
    };
}