import { Info, ClipboardCheck, Loader2 } from 'lucide-react';
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import { type EmployeeOption } from '../types/leave-coverage-types';

interface ManagerAssignModalProps {
    open: boolean;
    employeeOptions: EmployeeOption[];
    assignToUserId: string;
    onAssignToUserIdChange: (val: string) => void;
    onCancel: () => void;
    onSubmit: () => void;
    isSubmitting: boolean;
}

export function ManagerAssignModal({
    open,
    employeeOptions,
    assignToUserId,
    onAssignToUserIdChange,
    onCancel,
    onSubmit,
    isSubmitting,
}: ManagerAssignModalProps) {
    return (
        <HarmonyDialog
            open={open}
            onOpenChange={onCancel}
            title="Assign Coverage"
            description="Directly assign an employee to cover this shift"
            footerChildren={
                <div className="flex justify-end gap-3 w-full">
                    <Button variant="secondary" onClick={onCancel} disabled={isSubmitting}>Cancel</Button>
                    <Button disabled={isSubmitting || !assignToUserId} onClick={onSubmit}>
                        {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                        Assign Employee
                    </Button>
                </div>
            }
        >
            <div className="space-y-6">
                <div className="bg-primary/10 border border-primary/20 p-4 rounded-2xl flex gap-3">
                    <Info className="w-4 h-4 text-primary shrink-0 mt-0.5" />
                    <p className="text-[11px] font-medium text-primary leading-relaxed">
                        Assigning an employee will move the record to <span className="font-bold">Assigned</span> status. The employee must accept the assignment to confirm.
                    </p>
                </div>

                <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Select Backfill Employee</label>
                    <select
                        value={assignToUserId}
                        onChange={(e) => onAssignToUserIdChange(e.target.value)}
                        className="w-full px-5 py-3.5 bg-muted/50 border border-border rounded-[18px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none appearance-none cursor-pointer"
                    >
                        <option value="">Select Employee</option>
                        {employeeOptions.map((opt) => (
                            <option key={opt.id} value={opt.id}>
                                {opt.name}
                            </option>
                        ))}
                    </select>
                </div>
            </div>
        </HarmonyDialog>
    );
}

interface VerifyCoverageModalProps {
    open: boolean;
    verifyNotes: string;
    onVerifyNotesChange: (val: string) => void;
    onCancel: () => void;
    onSubmit: () => void;
    isSubmitting: boolean;
}

export function VerifyCoverageModal({
    open,
    verifyNotes,
    onVerifyNotesChange,
    onCancel,
    onSubmit,
    isSubmitting,
}: VerifyCoverageModalProps) {
    return (
        <HarmonyDialog
            open={open}
            onOpenChange={onCancel}
            title="Verify Coverage"
            description="Finalize the coverage record for payroll"
            onSubmit={onSubmit}
            submitLabel="Verify & Close"
            isSubmitting={isSubmitting}
        >
            <div className="space-y-5">
                <div className="bg-emerald-50 dark:bg-emerald-950/30 border border-emerald-100 dark:border-emerald-800 p-4 rounded-2xl flex gap-3">
                    <ClipboardCheck className="w-4 h-4 text-emerald-600 dark:text-emerald-400 shrink-0 mt-0.5" />
                    <p className="text-[11px] font-medium text-emerald-700 dark:text-emerald-300 leading-relaxed">
                        Verification confirms that the coverage was successfully performed. This record will be moved to <span className="font-bold">Verified</span>.
                    </p>
                </div>

                <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Verification Notes</label>
                    <textarea
                        rows={4}
                        placeholder="e.g. Coverage confirmed, shift completed successfully..."
                        value={verifyNotes}
                        onChange={(e) => onVerifyNotesChange(e.target.value)}
                        className="w-full px-5 py-4 bg-muted/50 border border-border rounded-[24px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none resize-none"
                    />
                </div>
            </div>
        </HarmonyDialog>
    );
}
