export function formatDate(value?: string | null): string {
    if (!value) return '-';
    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return value;
    return d.toLocaleDateString();
}

export function getCurrentRole(): string {
    try {
        const raw = localStorage.getItem('user');
        if (!raw) return '';
        const parsed = JSON.parse(raw);
        return parsed?.role ?? '';
    } catch {
        return '';
    }
}

export function mapEmployeeOptions(data: unknown): EmployeeOption[] {
    const employees = Array.isArray(data) ? data : [];
    return employees
        .map((employee: any) => {
            const id = employee.userProfileId || employee.id || employee.userId || '';
            const name =
                employee.fullName ||
                employee.name ||
                `${employee.firstName || ''} ${employee.lastName || ''}`.trim() ||
                employee.email ||
                id;
            return { id, name };
        })
        .filter((item: EmployeeOption) => Boolean(item.id));
}