import type { ReactNode } from 'react';
import type { Pagination } from '@/types/api';
import { TableHeader, TableBody, TableRow, TableHead, TableCell } from '@/components/ui/Table';
import { Button } from '@/shadcn/components/ui/button';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/shadcn/components/ui/select';

export interface ServerTableColumn<T> {
    key: string;
    header: string;
    className?: string;
    render: (row: T, rowIndex: number) => ReactNode;
}

interface ServerPaginationTableProps<T> {
    title?: string;
    description?: string;
    columns: Array<ServerTableColumn<T>>;
    rows: T[];
    rowKey: (row: T, rowIndex: number) => string;
    pagination: Pick<
        Pagination<unknown>,
        'pageIndex' | 'pageSize' | 'totalCount' | 'totalPages' | 'hasNextPage' | 'hasPreviousPage'
    >;
    isLoading?: boolean;
    emptyMessage?: string;
    errorMessage?: string | null;
    pageSizeOptions?: number[];
    onPageChange: (nextPage: number) => void;
    onPageSizeChange?: (nextPageSize: number) => void;
}

export function ServerPaginationTable<T>({
    title,
    description,
    columns,
    rows,
    rowKey,
    pagination,
    isLoading = false,
    emptyMessage = 'No records found.',
    errorMessage,
    pageSizeOptions = [10, 20, 50],
    onPageChange,
    onPageSizeChange,
}: ServerPaginationTableProps<T>) {
    const { pageIndex, pageSize, totalCount, totalPages, hasNextPage, hasPreviousPage } = pagination;
    const skeletonRows = Math.min(pageSize, 5);

    return (
        <section className="w-full overflow-hidden rounded-xl border border-border bg-card shadow-sm">
            {(title || description) && (
                <header className="border-b border-border bg-muted/30 px-5 py-3.5">
                    {title && <h2 className="text-sm font-semibold text-foreground">{title}</h2>}
                    {description && <p className="mt-0.5 text-xs text-muted-foreground">{description}</p>}
                </header>
            )}

            <div className="overflow-x-auto">
                <table className="min-w-full caption-bottom text-sm border-collapse">
                    <TableHeader>
                        <TableRow>
                            {columns.map((column) => (
                                <TableHead key={column.key} className={column.className}>
                                    {column.header}
                                </TableHead>
                            ))}
                        </TableRow>
                    </TableHeader>

                    <TableBody>
                        {isLoading && (
                            Array.from({ length: skeletonRows }).map((_, i) => (
                                <TableRow key={`skeleton-${i}`}>
                                    {columns.map((col) => (
                                        <TableCell key={col.key}>
                                            <div className="h-4 rounded bg-muted animate-pulse" />
                                        </TableCell>
                                    ))}
                                </TableRow>
                            ))
                        )}

                        {!isLoading && errorMessage && (
                            <TableRow>
                                <TableCell
                                    colSpan={columns.length}
                                    className="py-10 text-center text-destructive"
                                >
                                    {errorMessage}
                                </TableCell>
                            </TableRow>
                        )}

                        {!isLoading && !errorMessage && rows.length === 0 && (
                            <TableRow>
                                <TableCell
                                    colSpan={columns.length}
                                    className="py-10 text-center text-muted-foreground"
                                >
                                    {emptyMessage}
                                </TableCell>
                            </TableRow>
                        )}

                        {!isLoading && !errorMessage &&
                            rows.map((row, rowIndex) => (
                                <TableRow key={rowKey(row, rowIndex)}>
                                    {columns.map((column) => (
                                        <TableCell
                                            key={`${column.key}-${rowKey(row, rowIndex)}`}
                                            className={column.className}
                                        >
                                            {column.render(row, rowIndex)}
                                        </TableCell>
                                    ))}
                                </TableRow>
                            ))}
                    </TableBody>
                </table>
            </div>

            <footer className="flex flex-col gap-3 border-t border-border bg-muted/30 px-5 py-3 sm:flex-row sm:items-center sm:justify-between">
                <p className="text-sm text-muted-foreground">
                    Page <strong className="text-foreground">{pageIndex}</strong> of{' '}
                    <strong className="text-foreground">{totalPages || 1}</strong>
                    <span className="ml-2">({totalCount} total)</span>
                </p>

                <div className="flex flex-wrap items-center gap-2">
                    {onPageSizeChange && (
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <span>Rows</span>
                            <Select
                                value={String(pageSize)}
                                onValueChange={(v) => onPageSizeChange(Number(v))}
                                disabled={isLoading}
                            >
                                <SelectTrigger size="sm" className="w-[70px]">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    {pageSizeOptions.map((size) => (
                                        <SelectItem key={size} value={String(size)}>
                                            {size}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    )}

                    <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => onPageChange(Math.max(1, pageIndex - 1))}
                        disabled={!hasPreviousPage || isLoading}
                    >
                        Previous
                    </Button>

                    <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => onPageChange(pageIndex + 1)}
                        disabled={!hasNextPage || isLoading}
                    >
                        Next
                    </Button>
                </div>
            </footer>
        </section>
    );
}
