import React, { useState, useEffect } from 'react';
import { Calendar, AlertCircle, CheckCircle2, Loader2 } from 'lucide-react';
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import { LeaveSize, LeaveType } from '@/api/leaveService';
import { type LeaveCreateForm, type EmployeeOption } from '../types/leave-types';
import { leaveService } from '@/api/leaveService';

interface LeaveRequestModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (form: LeaveCreateForm) => void;
  isSubmitting: boolean;
  employeeOptions: EmployeeOption[];
  initialUserId?: string;
}

export const LeaveRequestModal: React.FC<LeaveRequestModalProps> = ({
  isOpen,
  onClose,
  onSubmit,
  isSubmitting,
  employeeOptions,
  initialUserId = '',
}) => {
  const [form, setForm] = useState<LeaveCreateForm>({
    userProfileId: initialUserId,
    leaveDate: '',
    leaveSize: LeaveSize.FullDay,
    leaveType: LeaveType.Planned,
    reason: '',
    notes: '',
  });

  const [isValidating, setIsValidating] = useState(false);
  const [balanceStatus, setBalanceStatus] = useState<{ isValid: boolean; message: string } | null>(null);

  // Sync initialUserId when it changes or when modal opens
  useEffect(() => {
    if (isOpen && initialUserId) {
        setForm(prev => ({ ...prev, userProfileId: initialUserId }));
    }
  }, [isOpen, initialUserId]);

  // Validate balance when date or size changes
  useEffect(() => {
    const validate = async () => {
      if (form.userProfileId && form.leaveDate) {
        setIsValidating(true);
        try {
          const size = form.leaveSize === LeaveSize.FullDay ? 1 : 0.5;
          const data = await leaveService.leaves.validateBalance(form.userProfileId, form.leaveDate, size);

          if (data.isValid) {
            setBalanceStatus({ isValid: true, message: data.message || 'Sufficient balance available for this request.' });
          } else {
            setBalanceStatus({ isValid: false, message: data.message || 'Insufficient balance. This will be marked as Unpaid Leave if approved.' });
          }
        } catch (e) {
          setBalanceStatus(null);
        } finally {
          setIsValidating(false);
        }
      }
    };

    const timer = setTimeout(validate, 500);
    return () => clearTimeout(timer);
  }, [form.leaveDate, form.leaveSize, form.userProfileId]);

  const handleFieldChange = (field: keyof LeaveCreateForm, value: any) => {
    setForm(prev => ({ ...prev, [field]: value }));
  };

  const isFormValid = form.userProfileId && form.leaveDate && form.reason.trim().length > 5;

  return (
    <HarmonyDialog
      open={isOpen}
      onOpenChange={onClose}
      title="Request Leave"
      description="Submit a new leave application for review"
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button variant="secondary" onClick={onClose}>Cancel</Button>
          <Button
            disabled={!isFormValid || isSubmitting || isValidating}
            onClick={() => onSubmit(form)}
          >
            {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
            Submit Request
          </Button>
        </div>
      }
    >
      <div className="space-y-6">
        {/* Employee Selection (For Admins) */}
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Employee</label>
          <select
            value={form.userProfileId}
            onChange={(e) => handleFieldChange('userProfileId', e.target.value)}
            className="w-full px-5 py-3.5 bg-muted/50 border border-border rounded-[18px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none appearance-none cursor-pointer"
          >
            <option value="">Select Employee</option>
            {employeeOptions.map(opt => <option key={opt.id} value={opt.id}>{opt.name}</option>)}
          </select>
        </div>

        {/* Date & Size */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Leave Date</label>
            <div className="relative">
              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground pointer-events-none" />
              <input
                type="date"
                value={form.leaveDate}
                onChange={(e) => handleFieldChange('leaveDate', e.target.value)}
                className="w-full pl-11 pr-5 py-3.5 bg-muted/50 border border-border rounded-[18px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none"
              />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Duration</label>
            <select
              value={form.leaveSize}
              onChange={(e) => handleFieldChange('leaveSize', Number(e.target.value))}
              className="w-full px-5 py-3.5 bg-muted/50 border border-border rounded-[18px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none appearance-none cursor-pointer"
            >
              <option value={LeaveSize.FullDay}>Full Day</option>
              <option value={LeaveSize.FirstHalf}>First Half (0.5)</option>
              <option value={LeaveSize.SecondHalf}>Second Half (0.5)</option>
            </select>
          </div>
        </div>

        {/* Balance Status */}
        {form.leaveDate && form.userProfileId && (
          <div className={`p-4 rounded-[20px] border transition-all duration-300 flex gap-3 ${
            isValidating ? 'bg-muted/50 border-border' :
            balanceStatus?.isValid ? 'bg-emerald-50/50 dark:bg-emerald-950/20 border-emerald-100 dark:border-emerald-800' : 'bg-amber-50/50 dark:bg-amber-950/20 border-amber-100 dark:border-amber-800'
          }`}>
            <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${
              isValidating ? 'bg-card text-muted-foreground' :
              balanceStatus?.isValid ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'
            }`}>
              {isValidating ? <Loader2 className="w-4 h-4 animate-spin" /> :
               balanceStatus?.isValid ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
            </div>
            <div className="min-w-0">
              <p className="text-[11px] font-black text-foreground tracking-tight leading-tight">
                {isValidating ? 'Verifying...' : balanceStatus?.isValid ? 'Balance Verified' : 'Balance Alert'}
              </p>
              <p className="text-[10px] font-medium text-muted-foreground mt-0.5 truncate">
                {isValidating ? 'Checking future entitlements...' : balanceStatus?.message}
              </p>
            </div>
          </div>
        )}

        {/* Reason */}
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Reason for Leave</label>
          <input
            type="text"
            placeholder="e.g. Family Function, Medical..."
            value={form.reason}
            onChange={(e) => handleFieldChange('reason', e.target.value)}
            className="w-full px-5 py-3.5 bg-muted/50 border border-border rounded-[18px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none"
          />
        </div>

        {/* Notes */}
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Additional Notes (Optional)</label>
          <textarea
            rows={3}
            placeholder="Any extra details..."
            value={form.notes}
            onChange={(e) => handleFieldChange('notes', e.target.value)}
            className="w-full px-5 py-3.5 bg-muted/50 border border-border rounded-[20px] text-sm font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none resize-none"
          />
        </div>
      </div>
    </HarmonyDialog>
  );
};
