import { LeaveCoveredStatus, type LeaveCoveredCreateDTO } from '@/api/leaveService';
import { Button } from '@/shadcn/components/ui/button';
import type { EmployeeOption } from '../types/leave-coverage-types';

interface CreateCoverageCardProps {
    createForm: LeaveCoveredCreateDTO;
    employeeOptions: EmployeeOption[];
    isSubmitting: boolean;
    onChange: (updater: (prev: LeaveCoveredCreateDTO) => LeaveCoveredCreateDTO) => void;
    onSubmit: () => void;
}

export function CreateCoverageCard({ createForm, employeeOptions, isSubmitting, onChange, onSubmit }: CreateCoverageCardProps) {
    return (
        <section className="section-card">
            <div className="section-card-header">
                <h2 className="section-card-title">New Coverage Record</h2>
            </div>
            <div className="p-5 space-y-4">
                <div className="grid gap-4">
                    <div>
                        <label className="form-label">Leave ID</label>
                        <input
                            type="text"
                            value={createForm.leaveId}
                            onChange={(event) => onChange((prev) => ({ ...prev, leaveId: event.target.value }))}
                            className="form-input"
                            placeholder="Associated Request ID"
                        />
                    </div>

                    <div>
                        <label className="form-label">Covered For</label>
                        <select
                            value={createForm.coveredForUserId}
                            onChange={(event) => onChange((prev) => ({ ...prev, coveredForUserId: event.target.value }))}
                            className="form-input"
                        >
                            <option value="">Select employee</option>
                            {employeeOptions.map((option) => (
                                <option key={option.id} value={option.id}>
                                    {option.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="form-label">Shift Date</label>
                        <input
                            type="date"
                            value={createForm.date}
                            onChange={(event) => onChange((prev) => ({ ...prev, date: event.target.value }))}
                            className="form-input"
                        />
                    </div>

                    <div>
                        <label className="form-label">Description</label>
                        <input
                            type="text"
                            maxLength={500}
                            value={createForm.shiftDescription}
                            onChange={(event) => onChange((prev) => ({ ...prev, shiftDescription: event.target.value }))}
                            className="form-input"
                            placeholder="e.g. Night Shift, Desk Duty"
                        />
                    </div>
                </div>

                <Button type="button" className="w-full" disabled={isSubmitting} onClick={onSubmit}>
                    {isSubmitting ? 'Creating...' : 'Post Coverage'}
                </Button>
            </div>
        </section>
    );
}

interface CoverageFiltersCardProps {
    statusFilter: string;
    leaveIdFilter: string;
    coveredForFilter: string;
    employeeOptions: EmployeeOption[];
    onStatusFilterChange: (value: string) => void;
    onLeaveIdFilterChange: (value: string) => void;
    onCoveredForFilterChange: (value: string) => void;
    onReset: () => void;
}

export function CoverageFiltersCard({
    statusFilter,
    leaveIdFilter,
    coveredForFilter,
    employeeOptions,
    onStatusFilterChange,
    onLeaveIdFilterChange,
    onCoveredForFilterChange,
}: CoverageFiltersCardProps) {
    return (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            <div className="flex flex-col gap-1">
                <label className="form-label">Status</label>
                <select
                    value={statusFilter}
                    onChange={(event) => onStatusFilterChange(event.target.value)}
                    className="form-input"
                >
                    <option value="">All Statuses</option>
                    <option value={LeaveCoveredStatus.Open}>Open</option>
                    <option value={LeaveCoveredStatus.Assigned}>Assigned</option>
                    <option value={LeaveCoveredStatus.Accepted}>Accepted</option>
                    <option value={LeaveCoveredStatus.Verified}>Verified</option>
                    <option value={LeaveCoveredStatus.Cancelled}>Cancelled</option>
                </select>
            </div>

            <div className="flex flex-col gap-1">
                <label className="form-label">Leave ID</label>
                <input
                    type="text"
                    value={leaveIdFilter}
                    onChange={(event) => onLeaveIdFilterChange(event.target.value)}
                    className="form-input"
                    placeholder="Search by ID"
                />
            </div>

            <div className="flex flex-col gap-1">
                <label className="form-label">Employee</label>
                <select
                    value={coveredForFilter}
                    onChange={(event) => onCoveredForFilterChange(event.target.value)}
                    className="form-input"
                >
                    <option value="">All Users</option>
                    {employeeOptions.map((option) => (
                        <option key={option.id} value={option.id}>
                            {option.name}
                        </option>
                    ))}
                </select>
            </div>
        </div>
    );
}