import { type LeaveCoveredStatus, leaveEnumLabels, type LeaveStatus } from '@/api/leaveService';

type StatusKind = 'leave' | 'coverage';
type StatusSize = 'sm' | 'md';

interface WorkflowStatusChipProps {
    kind: StatusKind;
    value: LeaveStatus | LeaveCoveredStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

const SIZE_CLASS: Record<StatusSize, string> = {
    sm: 'px-2 py-0.5 text-xs',
    md: 'px-2.5 py-1 text-sm',
};

const LEAVE_STATUS_CLASS: Record<number, string> = {
    0: 'bg-sky-50 text-sky-700 border-sky-200 dark:bg-sky-950/60 dark:text-sky-300 dark:border-sky-800',
    1: 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/60 dark:text-emerald-300 dark:border-emerald-800',
    2: 'bg-rose-50 text-rose-700 border-rose-200 dark:bg-rose-950/60 dark:text-rose-300 dark:border-rose-800',
    3: 'bg-primary/10 text-primary border-primary/20',
    4: 'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-950/60 dark:text-amber-300 dark:border-amber-800',
    5: 'bg-muted text-muted-foreground border-border',
};

const COVERAGE_STATUS_CLASS: Record<number, string> = {
    0: 'bg-muted text-muted-foreground border-border',
    1: 'bg-primary/10 text-primary border-primary/20',
    2: 'bg-violet-50 text-violet-700 border-violet-200 dark:bg-violet-950/60 dark:text-violet-300 dark:border-violet-800',
    3: 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/60 dark:text-emerald-300 dark:border-emerald-800',
    4: 'bg-rose-50 text-rose-700 border-rose-200 dark:bg-rose-950/60 dark:text-rose-300 dark:border-rose-800',
};

const FALLBACK_CLASS = 'bg-muted text-muted-foreground border-border';

function toStatusNumber(value: WorkflowStatusChipProps['value']): number | null {
    if (value === null || value === undefined) return null;
    if (typeof value === 'number') return value;
    if (typeof value === 'string') {
        const parsed = Number(value);
        return Number.isNaN(parsed) ? null : parsed;
    }
    return null;
}

function getLabel(kind: StatusKind, value: number | null, fallback: WorkflowStatusChipProps['value']): string {
    if (value === null) return String(fallback ?? 'Unknown');

    if (kind === 'leave') {
        return leaveEnumLabels.leaveStatus[value as LeaveStatus] ?? String(value);
    }

    return leaveEnumLabels.leaveCoveredStatus[value as LeaveCoveredStatus] ?? String(value);
}

export function WorkflowStatusChip({ kind, value, size = 'md', className = '' }: WorkflowStatusChipProps) {
    const statusNumber = toStatusNumber(value);
    const label = getLabel(kind, statusNumber, value);
    const toneClass =
        statusNumber === null
            ? FALLBACK_CLASS
            : kind === 'leave'
                ? (LEAVE_STATUS_CLASS[statusNumber] ?? FALLBACK_CLASS)
                : (COVERAGE_STATUS_CLASS[statusNumber] ?? FALLBACK_CLASS);

    return (
        <span
            className={`inline-flex items-center rounded-full border font-semibold tracking-tight ${SIZE_CLASS[size]} ${toneClass} ${className}`}
            title={label}
        >
            {label}
        </span>
    );
}

interface LeaveStatusChipProps {
    value: LeaveStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

export function LeaveStatusChip({ value, size = 'md', className }: LeaveStatusChipProps) {
    return <WorkflowStatusChip kind="leave" value={value} size={size} className={className} />;
}

interface LeaveCoveredStatusChipProps {
    value: LeaveCoveredStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

export function LeaveCoveredStatusChip({ value, size = 'md', className }: LeaveCoveredStatusChipProps) {
    return <WorkflowStatusChip kind="coverage" value={value} size={size} className={className} />;
}
